  ('locality-e3452428-moex-00324', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '下列何者得由行政機關與人民以行政契約辦理之？', '["公務員之免職", "國家考試是否錄取", "兵役機關徵召役男入伍", "稅捐機關依職權調查後，仍無法確定納稅義務人有無海外所得，而與人民簽訂和解契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00325', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於行政指導之敘述，下列何者錯誤？', '["行政指導乃不具法律上強制力之行為", "人民於必要時得請求以書面方式為之", "僅限於要求特定作為，不作為則非其對象", "行政指導在分類上可以歸納為事實行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00326', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於行政罰裁處之敘述，下列何者錯誤？', '["甲為乙利益而實施違反行政法上義務之行為，甲應受處罰，而乙受有財產上利益卻不須受處罰， 為裁處之主管機關得對乙所受財產上利益價值範圍內酌予追繳", "丙因違反行政法義務，行政機關依法得沒入其使用之物，但於行政機關沒入前，丙將該物毀壞 致無法沒入，行政機關得裁處沒入該物之價額", "丁為10歲之國民小學學童，下課後單獨搭乘大眾捷運，因飢餓難耐取出背包零食食用，主管機 關依違反大眾捷運法科處罰鍰", "戊平日均搭乘大眾捷運返家，其因心情欠佳，於飲酒後，在搭乘大眾捷運時，擅自開啟車門， 其雖已意識不清，仍可予以處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00327', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '下列何者非屬直接強制方法？', '["封閉住宅", "拘提管收", "解除占有", "註銷證照"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00328', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '有關行政程序所生之費用，下列敘述何者錯誤？', '["由行政機關負擔", "證人之費用，不得請求行政機關預行酌給之", "鑑定人得向行政機關請求法定之日費及旅費，並得請求相當之報酬", "因可歸責於當事人之事由，致程序有顯著之延滯者，其因延滯所生之費用，由其負擔"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00329', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '甲向某市政府申請核發建造執照，遭否准。甲不服，遂提起訴願。於訴願審議中，市政府撤銷原 否准決定，並為核發建造執照之處分。此時受理訴願機關依法應為如何之決定？', '["訴願不受理", "以訴願無理由駁回", "撤銷原處分，自為核定處分", "以情況決定駁回"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00330', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '下列何種行政訴訟之第一審，非屬地方法院行政訴訟庭管轄？', '["行政契約新臺幣20萬元以下履約爭議之事件", "內政部移民署暫時收容之事件", "稅捐機關核課新臺幣72萬元之事件", "受刑人不服監獄管教處分之事件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00331', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '依最高行政法院大法庭裁定見解，被徵收土地所有權人對主管機關所核定之徵收補償價額不服， 循序提起行政訴訟時，應提起之訴訟類型為何？', '["一般給付訴訟", "撤銷處分之訴", "確認處分違法之訴", "課予義務訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00332', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於行政訴訟法中都市計畫審查程序之規定，下列何者錯誤？', '["都市計畫審查訴訟，應於都市計畫發布後1年之不變期間內提起", "被告收受起訴狀繕本後，應於2個月內重新檢討原告請求宣告無效之都市計畫是否合法", "都市計畫審查訴訟，專屬都市計畫區所在地之高等行政法院管轄", "人民認為都市計畫違法或不當，而直接損害其權利者，得提起訴訟，請求宣告該都市計畫無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00333', 'locality-e3452428', 'locality-e3452428-moex-110-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '下列何種情形人民不得主張損失補償？', '["騎樓之所有權人，應開放其騎樓供公眾通行使用", "都市計畫道路用地之所有權人，在依法徵收以前，其用地遭到政府埋設地下設施物", "野生動物保護區土地之所有權人，在依法徵收以前，應以主管機關公告之方法提供野生動物棲 息環境", "水道沿岸之私有土地建造物，經主管機關認為有礙水流者，命所有權人大幅度修改"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:19+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "302", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL)
